                _ => false,
            },
            Command::Org { action } => match action {
                OrganizationAction::List { json } | OrganizationAction::Show { json, .. } => *json,
            },
            Command::Auth { action, .. } => match action {
                Some(AuthAction::Status { json }) => *json,
                _ => false,
