use crate::api::client::ApiClient;
use crate::models::{ResultWithDefaultError, TimeEntry};
use crate::utilities::normalize_time_entry_list_filters;
use chrono::Datelike;
use std::collections::BTreeMap;

const BILLING_UNIT_SECONDS: i64 = 15 * 60;
const MINIMUM_ENTRY_SECONDS: i64 = 30 * 60;

pub struct InvoiceMonthlyCommand;

/// Apply the invoice rule to one stopped entry: round up independently to a
/// 15-minute unit, then enforce the 30-minute minimum.
fn invoice_seconds(entry: &TimeEntry) -> i64 {
    let duration = entry.duration.max(0);
    let units = duration / BILLING_UNIT_SECONDS + i64::from(duration % BILLING_UNIT_SECONDS != 0);
    let rounded = units * BILLING_UNIT_SECONDS;
    rounded.max(MINIMUM_ENTRY_SECONDS)
}

fn monthly_totals(entries: impl IntoIterator<Item = TimeEntry>) -> BTreeMap<String, i64> {
    let mut totals = BTreeMap::new();
    for entry in entries {
        if !entry.billable || entry.stop.is_none() {
            continue;
        }
        let month = format!("{:04}-{:02}", entry.start.year(), entry.start.month());
        *totals.entry(month).or_insert(0) += invoice_seconds(&entry);
    }
    totals
}

fn print_totals(totals: &BTreeMap<String, i64>) {
    if totals.is_empty() {
        println!("(no data)");
        return;
    }

    let total: i64 = totals.values().sum();
    for (month, seconds) in totals {
        println!("{month}  {seconds}s");
    }
    println!("Total  {total}s");
}

impl InvoiceMonthlyCommand {
    pub async fn execute(
        api_client: impl ApiClient,
        since: Option<String>,
        until: Option<String>,
    ) -> ResultWithDefaultError<()> {
        let (since, until) = normalize_time_entry_list_filters(since, until)?;
        let entries = api_client
            .get_time_entries_filtered_minimal(since, until)
            .await?;
        print_totals(&monthly_totals(entries));
        Ok(())
    }
}

